import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';

function Navbar() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const { theme, toggleTheme } = useTheme();

  const getInitials = (name) => {
    if (!name) return '?';
    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  return (
    <nav className="navbar">
      <div className="navbar-left">
        <div className="cloud-logo">
          <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M6.5 19C3.46243 19 1 16.5376 1 13.5C1 10.6683 3.10635 8.30483 5.9091 8.01919C6.34608 5.07433 8.95644 3 12 3C15.2386 3 17.7938 5.43041 17.9934 8.61419C20.3416 8.87201 22 10.8028 22 13.1944C22 16.0732 19.5208 18.5 16.5 18.5H6.5C3.46243 18.5 1 15.5376 1 12.5C1 9.46243 3.46243 7 6.5 7C6.6 7 6.69907 7.00335 6.79691 7.0098C7.09419 4.12753 9.53634 2 12.5 2C15.5376 2 18 4.46243 18 7.5C18 7.6 17.9966 7.69907 17.9902 7.79691C20.8725 8.09419 23 10.5363 23 13.5C23 16.5376 20.5376 19 17.5 19H6.5Z" fill="var(--primary)"/>
          </svg>
        </div>
      </div>
      <div className="navbar-right">
        {user ? (
          <>
            <button
              className="navbar-btn"
              onClick={() => navigate('/settings')}
              title="Manage Account"
            >
              <i className="fa-solid fa-user-gear"></i>
              <span>Manage Account</span>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={() => navigate('/settings')}
              title="User Profile"
            >
              <div className="user-avatar">
                {getInitials(user.fullName)}
              </div>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={() => navigate('/settings')}
              title="Settings"
            >
              <i className="fa-solid fa-gear"></i>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={toggleTheme}
              title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
            >
              <i className={`fa-solid ${theme === 'light' ? 'fa-moon' : 'fa-sun'}`}></i>
            </button>

            <button
              className="navbar-btn"
              onClick={logout}
              title="Sign Out"
            >
              <i className="fa-solid fa-right-from-bracket"></i>
              <span>Sign Out</span>
            </button>
          </>
        ) : (
          <>
            <button
              className="navbar-btn navbar-btn-icon"
              onClick={toggleTheme}
              title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
            >
              <i className={`fa-solid ${theme === 'light' ? 'fa-moon' : 'fa-sun'}`}></i>
            </button>

            <button
              className="btn btn-primary"
              onClick={() => navigate('/auth')}
              style={{ borderRadius: '20px', padding: '6px 18px', fontSize: '13px', fontWeight: 500 }}
            >
              <i className="fa-solid fa-user" style={{ fontSize: '13px' }}></i>
              <span>Sign In</span>
            </button>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
